t = int(input())
for _ in range(t):
    n = int(input())
    a = list(map(int, input().split()))

    best = float('inf')

    for c1 in range(3):
        for c2 in range(3):
            c3 = 0
            valid = True
            for x in a:
                min_coins3 = float('inf')
                for use1 in range(c1 + 1):
                    for use2 in range(c2 + 1):
                        rem = x - use1 - 2 * use2
                        if rem >= 0 and rem % 3 == 0:
                            min_coins3 = min(min_coins3, rem // 3)
                if min_coins3 == float('inf'):
                    valid = False
                    break
                c3 = max(c3, min_coins3)
            if valid:
                best = min(best, c1 + c2 + c3)

    print(best)
